impl Solution { pub fn knight_probability(n: i32, k: i32, row: i32, column: i32) -> f64 { let n = n as usize; let mut black_dp = vec![vec![1.0; n]; n]; let moves = [(-2,-1),(-2,1),(-1,-2),(-1,2),(1,-2),(1,2),(2,-1),(2,1)]; for _ in 0..k { let mut black_next = vec![vec![0.0; n]; n]; for i in 0..n { for j in 0..n { for &(di, dj) in &moves { let (ni, nj) = (i as i32 + di, j as i32 + dj); if ni >= 0 && ni < n as i32 && nj >= 0 && nj < n as i32 { black_next[i][j] += black_dp[ni as usize][nj as usize] / 8.0; } } } } black_dp = black_next; } black_dp[row as usize][column as usize] } }
